#include <stdio.h>
#include <math.h>

int solveJosephus(int n) {
    if (n == 1) return 1;
    int p = log2(n);
    return 2 * (n - (1 << p)) + 1;
}

int main() {
    int t, n;
    scanf("%d", &t);

    while (t--) {
        scanf("%d", &n);

        printf("%d\n", solveJosephus(n)); 
    }

    return 0;
}

